const EASE = [0.4, 0, 0.2, 1] as const; // mirrors --ease

// Wordmark rendered height as a fraction of the glyph height. EN sits in the
// horizontal lockup; AR is the subordinate line in the bilingual/vertical stack.
// AR_SOLO sits on its OWN horizontal lockup (no EN above it), so it carries the
// full brand weight and renders larger, tuned against new_full_logo_arabic.png
// (reference AR wordmark ≈ 0.70× the glyph height vs EN ≈ 0.63×).
// Tuned by eye against the glyph in the sidebar and login lockups.
const EN_WORDMARK_SCALE = 0.66;
const AR_WORDMARK_SCALE = 0.44;
const AR_SOLO_WORDMARK_SCALE = 0.72;

// Horizontal-lockup geometry, measured off the reference lockups: a thin
// emerald rule (the reference divider samples to a dark emerald that maps to
// --color-accent-700) sits between the glyph and the wordmark at ~0.8× the
// glyph height, with a symmetric gap on each side (~0.17× the glyph height).
const LOCKUP_GAP = 0.17;
const DIVIDER_HEIGHT = 0.8;

function LockupDivider({ height, mono }: { height: number; mono: boolean }) {
  return (
    <span
      aria-hidden="true"
      className="shrink-0 rounded-full"
      style={{
        width: Math.max(1, Math.round(height * 0.045)),
        height: height * DIVIDER_HEIGHT,
        backgroundColor: mono ? "currentColor" : "var(--color-accent-700)",
        opacity: mono ? 0.45 : 1,
      }}
    />
  );
}

function Glyph({
  height,
  mono,
  play,
  decorative,
  title,
}: {
  height: number;
  mono: boolean;
  play: boolean;
  decorative: boolean;
  title: string;
}) {
  const navy = mono ? "currentColor" : "var(--color-navy)";
  const accent = mono ? "currentColor" : "var(--color-accent)";
  const Path = (play ? motion.path : "path") as React.ElementType;

  const rise = (i: number) =>
    play
      ? {
          initial: { opacity: 0, y: 24 },
          animate: { opacity: 1, y: 0 },
          transition: { duration: 0.24, ease: EASE, delay: 0.05 * i },
        }
      : {};
  const sweep = play
    ? {
        initial: { opacity: 0, y: 18 },
        animate: { opacity: 1, y: 0 },
        transition: { duration: 0.16, ease: EASE, delay: 0.22 },
      }
    : {};

  return (
    <svg
      viewBox={`0 0 ${GLYPH_VB_W} ${GLYPH_VB_H}`}
      height={height}
      width={(height * GLYPH_VB_W) / GLYPH_VB_H}
      role={decorative ? undefined : "img"}
      aria-label={decorative ? undefined : title}
      aria-hidden={decorative || undefined}
    >
      {NAVY_PATHS.map((d, i) => (
        <Path key={i} d={d} fill={navy} {...rise(i)} />
      ))}
      <Path d={CHECK} fill={accent} {...sweep} />
    </svg>
  );
}

function Wordmark({
  art,
  height,
  fill,
  label,
}: {
  art: { w: number; h: number; d: string };
  height: number;
  fill: string;
  /** accessible name when the wordmark carries the mark's label; omit to hide. */
  label?: string;
}) {
  return (
    <svg
      viewBox={`0 0 ${art.w} ${art.h}`}
      height={height}
      width={(height * art.w) / art.h}
      role={label ? "img" : undefined}
      aria-label={label}
      aria-hidden={label ? undefined : true}
    >
      <path d={art.d} fill={fill} fillRule="evenodd" />
    </svg>
  );
}

export type LogoVariant =
  "icon" | "horizontal" | "horizontal-ar" | "horizontal-bilingual" | "vertical";
export type LogoTone = "brand" | "mono";

export function Logo({
  variant = "horizontal",
  tone = "brand",
  animated = false,
  size,
  decorative = false,
  title = "Faheem",
  className,
}: {
  variant?: LogoVariant;
  tone?: LogoTone;
  animated?: boolean;
  /** icon height in px; the wordmark scales from it. */
  size?: number;
  decorative?: boolean;
  title?: string;
  className?: string;
}) {
  const reduce = useReducedMotion();
  const play = animated && !reduce;
  const mono = tone === "mono";
  const iconHeight =
    size ?? (variant === "icon" || variant === "vertical" ? 40 : 30);
  const wordFill = mono ? "currentColor" : "var(--color-navy)";

  const glyph = (
    <Glyph
      height={iconHeight}
      mono={mono}
      play={play}
      decorative={decorative || variant !== "icon"}
      title={title}
    />
  );

  if (variant === "icon") {
    return <span className={cn("inline-flex", className)}>{glyph}</span>;
  }

  const enWord = (
    <Wordmark
      art={WORDMARK_EN}
      height={iconHeight * EN_WORDMARK_SCALE}
      fill={wordFill}
      label={title}
    />
  );
  const arWord = (
    <Wordmark
      art={WORDMARK_AR}
      height={iconHeight * AR_WORDMARK_SCALE}
      fill={wordFill}
    />
  );

  if (variant === "vertical") {
    return (
      <span
        className={cn("inline-flex flex-col items-center gap-2", className)}
      >
        {glyph}
        <span className="inline-flex flex-col items-center gap-1.5">
          {enWord}
          {arWord}
        </span>
      </span>
    );
  }

  // horizontal / horizontal-ar / horizontal-bilingual: glyph · divider · wordmark.
  // Under RTL the flex row reverses, so horizontal-ar puts the glyph on the
  // leading (right) edge exactly as the Arabic reference lockup reads.
  const arSoloWord = (
    <Wordmark
      art={WORDMARK_AR}
      height={iconHeight * AR_SOLO_WORDMARK_SCALE}
      fill={wordFill}
      label={title}
    />
  );

  return (
    <span
      className={cn("inline-flex items-center", className)}
      style={{ gap: iconHeight * LOCKUP_GAP }}
    >
      {glyph}
      <LockupDivider height={iconHeight} mono={mono} />
      {variant === "horizontal-ar" ? (
        arSoloWord
      ) : variant === "horizontal-bilingual" ? (
        <span className="inline-flex flex-col items-start gap-1">
          {enWord}
          {arWord}
        </span>
      ) : (
        enWord
      )}
    </span>
  );
}
